public class BlockchainTier {
 private String accessType;

 public BlockchainTier(String accessType) {
 this.accessType = accessType;
 }

 public String determineTier() {
 if (accessType.equals('public')) {
 return 'Public Blockchain';
 } else if (accessType.equals('private')) {
 return 'Private Blockchain';
 } else if (accessType.equals('consortium')) {
 return 'Consortium Blockchain';
 }
 }

 // Example usage
 public static void main(String[] args) {
 BlockchainTier blockchainTier = new BlockchainTier('public');
 System.out.println(blockchainTier.determineTier());
 }
}
